import org.junit.jupiter.api.Test
import org.junit.jupiter.params.ParameterizedTest
import org.junit.jupiter.params.provider.ValueSource

/**
 * Tests for mutable collection property naming.
 * According to https://developer.android.com/kotlin/style-guide#constant_names
 * mutable collections should not use SCREAMING_SNAKE_CASE because their contents can be modified.
 */
class PropertyNamingRuleMutableCollectionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Nested
    inner class `Given a mutable collection property in an object` {
        @ParameterizedTest(name = "Type: {0}")
        @ValueSource(
            strings = [
                "MutableList",
                "MutableSet",
                "MutableMap",
                "MutableCollection",
                "ArrayList",
                "LinkedList",
                "HashSet",
                "LinkedHashSet",
                "TreeSet",
                "HashMap",
                "LinkedHashMap",
                "TreeMap",
            ],
        )
        fun `Given a mutable collection property with lower camel case name then do not emit`(typeName: String) {
            val code =
                """
                object Foo {
                    val someCollection: $typeName<Any> = $typeName()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a MutableMap property with generic types and lower camel case name then do not emit`() {
            val code =
                """
                object DumObjectName {
                    val someMap: MutableMap<String, String> = mutableMapOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a mutable collection property with SCREAMING_SNAKE_CASE name then emit`() {
            val code =
                """
                object Foo {
                    val SOME_LIST: MutableList<String> = mutableListOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code)
                .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should start with a lowercase letter and use camel case")
        }
    }

    @Nested
    inner class `Given a mutable collection property in a companion object` {
        @Test
        fun `Given a MutableMap property with lower camel case name then do not emit`() {
            val code =
                """
                class Foo {
                    companion object {
                        val someMap: MutableMap<String, String> = mutableMapOf()
                    }
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a MutableList property with lower camel case name then do not emit`() {
            val code =
                """
                class Foo {
                    companion object {
                        val someList: MutableList<String> = mutableListOf()
                    }
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given a mutable collection property at top level` {
        @Test
        fun `Given a MutableMap property with lower camel case name then do not emit`() {
            val code =
                """
                val someMap: MutableMap<String, String> = mutableMapOf()
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a MutableList property with lower camel case name then do not emit`() {
            val code =
                """
                val someList: MutableList<String> = mutableListOf()
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a top level MutableList with SCREAMING_SNAKE_CASE then emit`() {
            val code =
                """
                val SOME_LIST: MutableList<String> = mutableListOf()
                """.trimIndent()
            propertyNamingRuleAssertThat(code)
                .hasLintViolationWithoutAutoCorrect(1, 5, "Property name should start with a lowercase letter and use camel case")
        }
    }

    @Nested
    inner class `Given a nullable mutable collection property` {
        @Test
        fun `Given a nullable MutableMap property with lower camel case name then do not emit`() {
            val code =
                """
                object Foo {
                    val someMap: MutableMap<String, String>? = null
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given a nullable MutableList property at top level with lower camel case name then do not emit`() {
            val code =
                """
                val someList: MutableList<String>? = null
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given immutable collection properties should still require SCREAMING_SNAKE_CASE` {
        @Test
        fun `Given a List property with lower camel case name in object then emit`() {
            val code =
                """
                object Foo {
                    val someList: List<String> = listOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code)
                .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should use the screaming snake case notation when the value can not be changed")
        }

        @Test
        fun `Given a Map property with lower camel case name at top level then emit`() {
            val code =
                """
                val someMap: Map<String, String> = mapOf()
                """.trimIndent()
            propertyNamingRuleAssertThat(code)
                .hasLintViolationWithoutAutoCorrect(1, 5, "Property name should use the screaming snake case notation when the value can not be changed")
        }

        @Test
        fun `Given a Set property with SCREAMING_SNAKE_CASE name in object then do not emit`() {
            val code =
                """
                object Foo {
                    val SOME_SET: Set<String> = setOf()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }
    }

    @Nested
    inner class `Given other mutable types` {
        @Test
        fun `Given a StringBuilder property with lower camel case name then do not emit`() {
            val code =
                """
                object Foo {
                    val builder: StringBuilder = StringBuilder()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }

        @Test
        fun `Given an ArrayDeque property with lower camel case name then do not emit`() {
            val code =
                """
                object Foo {
                    val deque: ArrayDeque<String> = ArrayDeque()
                }
                """.trimIndent()
            propertyNamingRuleAssertThat(code).hasNoLintViolations()
        }
    }
}
